={{
(() => {
  const resumo = $('Start').first().json.inputs?.resumo_lead || {};

  const linhas = Object.entries(resumo).map(([k, v]) => {
    let valor = v;

    if (valor === null || valor === undefined) valor = '';
    else if (typeof valor === 'object') valor = JSON.stringify(valor);

    return `${k}: ${valor}`;
  });

  return {
    custom_attributes: {
      lead_summary: "⬇️Resumo do Lead⬇️\n" + linhas.join('\n')
    }
  };
})()
}}

={{
(() => {
  const isFup = !!$('Start').first().json.opcoes?.eh_fup
    || $('Start').first().json.resposta?.evento_sistema_novo === 'FOLLOWUP_DISPARADO';

  const modality = $('Start').first().json.message?.message_modality || 'text_only';
  const messageId = $('Start').first().json.chatwoot?.message_id;

  const textoResposta =
    $('Start').first().json.resposta?.texto_resposta
    || $('Start').first().json.resposta?.message_fup
    || $('Start').first().json.message?.clean_answer
    || (
      Array.isArray($('Start').first().json.inputs?.mensagens_resposta)
        ? $('Start').first().json.inputs.mensagens_resposta.filter(Boolean).join('\n\n')
        : ''
    );

  return {
    content: textoResposta,
    message_type: "outgoing",
    private: false,
    content_type: "text",
    content_attributes: (!isFup && modality !== 'text_only' && messageId)
      ? { in_reply_to: messageId }
      : {}
  };
})()
}}

