      attachment = 'Segue o Guia Auauzin: https://drive.google.com/file/d/1tfDMN4TKcp-nZgglwSxiTEdsXzmrNQ-2/view';
      break;
    default:
      attachment = 'Segue o Guia Auau: https://drive.google.com/file/d/1R8aZ6YK0JRJO00Od4hXqLEbf7PTwp6_z/view';
      break;
  }

  return {
    content: attachment,
    message_type: 'outgoing',
    private: false,
    content_type: 'text',
  };
})()
}}

={{
(() => {
  const ehFup = !!$('Start').first().json.opcoes?.eh_fup;

  let texto =
    $('Start').first().json.opcoes?.nota_privada_texto
    || '';

  if (!texto && ehFup) {
    const tipo = $('Start').first().json.resposta?.tipo_followup || '';
    const resumo = $('Start').first().json.resposta?.resumo_followup || '';
    const msg = $('Start').first().json.resposta?.texto_resposta || '';

    texto =
`[FUP BRUNA]
Tipo: ${tipo}
Resumo: ${resumo}
Mensagem:
${msg}`;
  }

  return {
    content: texto,
    message_type: "outgoing",
    private: true,
    content_type: "text"
  };
})()
}}

