  cao_reativo,
  possui_relatorio_veterinario,
  unidade_preferida,
  servico_interesse,
  origem_lead,
  origem_detalhada,
  status_lead,
  ultima_intencao,
  evento_sistema_atual,
  apto_para_avaliacao,
  motivo_pre_reprovacao,
  data_checkin_desejada,
