  arquivo_comprovante_referencia,
  data_hora_avaliacao,
  data_hora_pre_reserva,
  pre_reserva_criada,
  responsavel_humano,
  deve_repassar_humano,
  motivo_repasse,
  guia_enviado,
  data_ultima_mensagem_lead,
  data_ultima_mensagem_bruna,
  data_ultima_interacao,
  mensagem_ultima_lead,
  mensagem_ultima_bruna,
  resumo_lead_json,
  resumo_interno_repasse_json,
  payload_ultima_resposta_json,
  dados_origem_json,
  etiquetas_chatwoot_json,
  versao_regras_negocio,
  versao_contrato_payload,
  contador_followup,
  tipo_ultimo_followup,
  ultimo_followup_em,
  account_id_chatwoot,
  contact_id_chatwoot,
  conversation_id_chatwoot,
  encerrado
) VALUES (
  {{ "'" + String($('Start').first().json.resposta.phone || $('Start').first().json.lead?.phone || '').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ $('Start').first().json.resposta.chat_history_uuid ? "'" + String($('Start').first().json.resposta.chat_history_uuid).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : ($('Start').first().json.chatwoot?.chat_history_uuid ? "'" + String($('Start').first().json.chatwoot.chat_history_uuid).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL') }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.resumo_lead?.tutor_nome
      || $('Start').first().json.resposta?.resumo_lead_json?.tutor_nome
      || $('Start').first().json.lead?.sender_name
      || '';
    return "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'";
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.email_tutor
      || $('Start').first().json.inputs?.resumo_lead?.email_tutor
      || $('Start').first().json.resposta?.resumo_lead_json?.email_tutor
      || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.resumo_lead?.cao_nome
      || $('Start').first().json.resposta?.resumo_lead_json?.cao_nome
      || '';
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.resumo_lead?.cao_idade_anos
      || $('Start').first().json.resposta?.resumo_lead_json?.cao_idade_anos
      || null;
    return (v !== '' && v !== null && v !== undefined) ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.idade_cao_texto
      || $('Start').first().json.inputs?.resumo_lead?.idade_cao_texto
      || $('Start').first().json.resposta?.resumo_lead_json?.idade_cao_texto
      || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.resumo_lead?.cao_raca
      || $('Start').first().json.resposta?.resumo_lead_json?.cao_raca
      || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.cao_porte || $('Start').first().json.resposta?.resumo_lead_json?.cao_porte || 'nao_definido').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.cao_sexo || $('Start').first().json.resposta?.resumo_lead_json?.cao_sexo || 'nao_informado').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.cao_castrado || $('Start').first().json.resposta?.resumo_lead_json?.cao_castrado || 'nao_informado').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.cao_no_cio || $('Start').first().json.resposta?.resumo_lead_json?.cao_no_cio || 'nao_informado').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.cao_vacinas_ok || $('Start').first().json.resposta?.resumo_lead_json?.cao_vacinas_ok || 'nao_informado').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.cao_antipulgas_ok || $('Start').first().json.resposta?.resumo_lead_json?.cao_antipulgas_ok || 'nao_informado').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.cao_vermifugacao_ok || $('Start').first().json.resposta?.resumo_lead_json?.cao_vermifugacao_ok || 'nao_informado').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.cao_sociavel || $('Start').first().json.resposta?.resumo_lead_json?.cao_sociavel || 'nao_informado').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.cao_reativo || $('Start').first().json.resposta?.resumo_lead_json?.cao_reativo || 'nao_informado').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.possui_relatorio_veterinario || $('Start').first().json.resposta?.resumo_lead_json?.possui_relatorio_veterinario || 'nao_informado').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.unidade_preferida || $('Start').first().json.resposta?.resumo_lead_json?.unidade_preferida || 'nao_definida').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.servico_interesse || $('Start').first().json.resposta?.resumo_lead_json?.servico_interesse || 'nao_definido').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},

  {{ (() => {
    const origem = $('Start').first().json.inputs?.origem_lead
      || $('Start').first().json.inputs?.resumo_lead?.origem_lead
      || $('Start').first().json.resposta?.resumo_lead_json?.origem_lead;
    if (origem) return "'" + String(origem).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'";
    const entry = String($('Start').first().json.lead?.entry_channel || '').toLowerCase();
    if (entry.includes('whatsapp') && entry.includes('meta')) return "'anuncio_whatsapp'";
    return "'outro'";
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.origem_detalhada
      || $('Start').first().json.lead?.entry_channel
      || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ "'" + String($('Start').first().json.resposta.status_lead_novo || $('Start').first().json.inputs?.status_lead || 'NOVO_LEAD').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ $('Start').first().json.resposta.ultima_intencao_nova ? "'" + String($('Start').first().json.resposta.ultima_intencao_nova).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : ($('Start').first().json.inputs?.ultima_intencao ? "'" + String($('Start').first().json.inputs.ultima_intencao).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL') }},
  {{ $('Start').first().json.resposta.evento_sistema_novo ? "'" + String($('Start').first().json.resposta.evento_sistema_novo).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : ($('Start').first().json.inputs?.evento_sistema ? "'" + String($('Start').first().json.inputs.evento_sistema).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL') }},

  {{ "'" + String($('Start').first().json.inputs?.apto_para_avaliacao || 'pendente').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.motivo_pre_reprovacao || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.data_checkin_desejada || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.data_checkout_desejada || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.resumo_lead?.data_desejada || $('Start').first().json.resposta?.resumo_lead_json?.data_desejada || $('Start').first().json.inputs?.data_desejada || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.resumo_lead?.periodo_desejado || $('Start').first().json.resposta?.resumo_lead_json?.periodo_desejado || $('Start').first().json.inputs?.periodo_desejado || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.valor_avaliacao;
    return (v !== '' && v !== null && v !== undefined) ? Number(v) : 100.00;
  })() }},

  {{ "'" + String($('Start').first().json.inputs?.status_pagamento || 'nao_solicitado').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ (() => {
    const v = $('Start').first().json.inputs?.comprovante_recebido ?? $('Start').first().json.inputs?.resumo_lead?.comprovante_recebido ?? $('Start').first().json.resposta?.resumo_lead_json?.comprovante_recebido ?? false;
    return v ? 1 : 0;
  })() }},
  {{ "'" + String($('Start').first().json.inputs?.tipo_comprovante || $('Start').first().json.inputs?.resumo_lead?.tipo_comprovante || $('Start').first().json.resposta?.resumo_lead_json?.tipo_comprovante || 'nao_informado').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.arquivo_comprovante_referencia || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.data_hora_avaliacao
      || $('Start').first().json.inputs?.resumo_interno_repasse?.data_hora_avaliacao
      || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const v = $('Start').first().json.inputs?.resumo_lead?.data_hora_pre_reserva
      || $('Start').first().json.resposta?.resumo_lead_json?.data_hora_pre_reserva
      || $('Start').first().json.inputs?.data_hora_pre_reserva
      || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const status = $('Start').first().json.resposta.status_lead_novo || '';
    const flag = $('Start').first().json.inputs?.pre_reserva_criada ?? false;
    const data = $('Start').first().json.inputs?.resumo_lead?.data_hora_pre_reserva || $('Start').first().json.resposta?.resumo_lead_json?.data_hora_pre_reserva || $('Start').first().json.inputs?.data_hora_pre_reserva;
    return (flag || status === 'PRE_RESERVA_CRIADA' || !!data) ? 1 : 0;
  })() }},

  {{ "'" + String($('Start').first().json.inputs?.resumo_lead?.responsavel_humano || $('Start').first().json.resposta?.resumo_lead_json?.responsavel_humano || 'Flavia').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ $('Start').first().json.inputs?.deve_repassar_humano ? 1 : 0 }},
  {{ (() => {
    const v = $('Start').first().json.inputs?.motivo_repasse || null;
    return v ? "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL';
  })() }},

  {{ (() => {
    const evento = $('Start').first().json.resposta.evento_sistema_novo || '';
    const flag = $('Start').first().json.inputs?.guia_enviado ?? false;
    return (flag || evento === 'GUIA_ENVIADO') ? 1 : 0;
  })() }},

  {{ $('Start').first().json.opcoes?.eh_fup ? 'NULL' : ($('Start').first().json.message?.created_at ? "'" + String($('Start').first().json.message.created_at).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NOW()') }},
  NOW(),
  NOW(),

  {{ $('Start').first().json.opcoes?.eh_fup ? 'NULL' : "'" + String($('Start').first().json.message?.content || '').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String(
      $('Start').first().json.resposta?.texto_resposta
      || $('Start').first().json.resposta?.message_fup
      || $('Start').first().json.message?.clean_answer
      || (
        Array.isArray($('Start').first().json.inputs?.mensagens_resposta)
          ? $('Start').first().json.inputs.mensagens_resposta.filter(Boolean).join('\n\n')
          : ''
      )
    ).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},

  CAST({{ "'" + JSON.stringify($('Start').first().json.resposta.resumo_lead_json || $('Start').first().json.inputs?.resumo_lead || {}).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }} AS JSON),
  CAST({{ "'" + JSON.stringify($('Start').first().json.inputs?.resumo_interno_repasse || {}).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }} AS JSON),
  CAST({{ "'" + JSON.stringify($('Start').first().json.resposta.payload_atual_json || {}).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }} AS JSON),

  CAST({{ "'" + JSON.stringify({
    entry_channel: $('Start').first().json.lead?.entry_channel || null,
    utms: $('Start').first().json.lead?.utms || {},
    sender_type: $('Start').first().json.lead?.sender_type || null,
    account_id_chatwoot: $('Start').first().json.chatwoot?.account_id || null,
    contact_id_chatwoot: $('Start').first().json.chatwoot?.contact_id || null,
    conversation_id_chatwoot: $('Start').first().json.chatwoot?.conversation_id || null
  }).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }} AS JSON),

  CAST({{ "'" + JSON.stringify($('Start').first().json.chatwoot?.labels || []).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }} AS JSON),

  {{ "'" + String($('Start').first().json.inputs?.versao_regras_negocio || 'v1').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},
  {{ "'" + String($('Start').first().json.inputs?.versao_contrato_payload || 'v1').replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" }},

  {{ $('Start').first().json.opcoes?.eh_fup ? 1 : 0 }},
  {{ $('Start').first().json.opcoes?.eh_fup && $('Start').first().json.resposta?.tipo_followup ? "'" + String($('Start').first().json.resposta.tipo_followup).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'" : 'NULL' }},
  {{ $('Start').first().json.opcoes?.eh_fup ? 'NOW()' : 'NULL' }},

  {{ $('Start').first().json.resposta.account_id_chatwoot || $('Start').first().json.chatwoot?.account_id || 'NULL' }},
  {{ $('Start').first().json.resposta.contact_id_chatwoot || $('Start').first().json.chatwoot?.contact_id || 'NULL' }},
  {{ $('Start').first().json.resposta.conversation_id_chatwoot || $('Start').first().json.chatwoot?.conversation_id || 'NULL' }},

  {{ (() => {
    const status = $('Start').first().json.resposta.status_lead_novo || '';
    return status.startsWith('ENCERRADO') ? 1 : 0;
  })() }}
)
