  data_checkin_desejada = VALUES(data_checkin_desejada),
  data_checkout_desejada = VALUES(data_checkout_desejada),
  data_desejada = VALUES(data_desejada),
  periodo_desejado = VALUES(periodo_desejado),
  valor_avaliacao = VALUES(valor_avaliacao),
  status_pagamento = VALUES(status_pagamento),
  comprovante_recebido = VALUES(comprovante_recebido),
  tipo_comprovante = VALUES(tipo_comprovante),
  arquivo_comprovante_referencia = VALUES(arquivo_comprovante_referencia),
  data_hora_avaliacao = VALUES(data_hora_avaliacao),
  data_hora_pre_reserva = VALUES(data_hora_pre_reserva),
  pre_reserva_criada = VALUES(pre_reserva_criada),
  responsavel_humano = VALUES(responsavel_humano),
  deve_repassar_humano = VALUES(deve_repassar_humano),
