const atuais = Array.isArray($('Start').first().json.chatwoot?.labels)
  ? $('Start').first().json.chatwoot.labels.map(x => String(x).trim()).filter(Boolean)
  : [];

const labelsNew = Array.isArray($('Start').first().json.opcoes?.labels_new)
  ? $('Start').first().json.opcoes.labels_new.map(x => String(x).trim()).filter(Boolean)
  : [];

const tagsAdd = Array.isArray($('Start').first().json.resposta?.tags_add)
  ? $('Start').first().json.resposta.tags_add.map(x => String(x).trim()).filter(Boolean)
  : [];

const tagsRemove = Array.isArray($('Start').first().json.resposta?.tags_remove)
  ? $('Start').first().json.resposta.tags_remove.map(x => String(x).trim()).filter(Boolean)
  : [];

const ehFup = !!$('Start').first().json.opcoes?.eh_fup;

let finais = labelsNew;

if (ehFup) {
  finais = [...new Set([
    ...atuais.filter(x => !tagsRemove.includes(x)),
    ...tagsAdd
  ])];
}

return [
  {
    json: {
      opcoes: {
        ...$('Start').first().json.opcoes,
        labels_new: finais
      }
    }
  }
];
